#include <stdio.h>
#include <limits.h>

int min(int a, int b) {
    return (a < b) ? a : b;
}

int M(int n, int p, int memo[][51]) {
    if (n == 0) return 0;
    if (p == 1) return (1LL << n) - 1;
    if (memo[n][p] != -1) return memo[n][p];
    int ans = INT_MAX;
    for (int i = 1; i < n; i++) {
        ans = min(ans, 2 * M(i, p, memo) + M(n - i, p - 1, memo));
    }
    memo[n][p] = ans;
    return ans;
}

int moveNumber(int n, int p, int k) {
    int memo[51][51];
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= p; j++) {
            memo[i][j] = -1;
        }
    }
    return M(n, p, memo) - M(n - k, p, memo);
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, P, K;
        scanf("%d %d %d", &N, &P, &K);
        printf("Case %d: %d\n", t + 1, moveNumber(N, P, K));
    }
    return 0;
}

