import java.util.Scanner;
public class Main {
    public static int min(int a, int b) {
        return (a < b) ? a : b;
    }

    public static int M(int n, int p, int[][] memo) {
        if (n == 0) return 0;
        if (p == 1) return (1L << n) - 1;
        if (memo[n][p] != -1) return memo[n][p];
        int ans = Integer.MAX_VALUE;
        for (int i = 1; i < n; i++) {
            ans = min(ans, 2 * M(i, p, memo) + M(n - i, p - 1, memo));
        }
        memo[n][p] = ans;
        return ans;
    }

    public static int moveNumber(int n, int p, int k) {
        int[][] memo = new int[51][51];
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= p; j++) {
                memo[i][j] = -1;
            }
        }
