const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function min(a, b) {
    return a < b ? a : b;
}

function M(n, p, memo) {
    if (n === 0) return 0;
    if (p === 1) return (1 << n) - 1;
    if (memo[n][p] !== -1) return memo[n][p];
    let ans = Infinity;
    for (let i = 1; i < n; i++) {
        ans = min(ans, 2 * M(i, p, memo) + M(n - i, p - 1, memo));
    }
    memo[n][p] = ans;
    return ans;
}

function moveNumber(n, p, k) {
    const memo = Array(51).fill(0).map(() => Array(51).fill(-1));
    return M(n, p, memo) - M(n - k, p, memo);
}

const T = parseInt(lines[idx++]);
for (let t = 0; t < T; t++) {
    const [N, P, K] = lines[idx++].trim().split(' ').map(Number);
    console.log(`Case ${t + 1}: ${moveNumber(N, P, K)}`);
}

